import org.owasp.encoder.Encode;

public class SecureXSSExample {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitizing and escaping user input before including it in the HTML output
        String sanitizedInput = Encode.forHtml(userInput);

        String htmlOutput = "<p>User input: " + sanitizedInput + "</p>";

        System.out.println(htmlOutput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
